def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 3, -1):
                for b in range(2, a + 5):
                    inner_sum = 0
                    for c in range(1, b + 1):
                        inner_sum += (ratio - a) ** (c / 2) * np.sin(ratio * c / (a + 1)) / (c + 0.7)
                    priority += inner_sum / (a * b) * np.cos(ratio * b / (a + 2))
            mod_factor = (np.exp(ratio - 8) * np.sin(ratio * 1.3)) ** 2.2
            priority += mod_factor
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.tanh(ratio) * 4
        elif 5 < ratio <= 8:
            acc = 0
            for p in range(2, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 3):
                    temp = ((ratio - p) ** 4) * np.cos(ratio * q / (p + 1)) / (q + 0.3)
                    acc += np.tanh(temp) * 1.5
            priority = acc + np.log(ratio) * 14 - np.tanh(ratio - 5) * 3.2
            for extra in range(1, 5):
                if (i + extra) % 2 == 0:
                    priority += np.sin(ratio * extra * i) * 0.4
                else:
                    priority -= np.cos(ratio * extra * i) * 0.4
        elif 2 <= ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.sin(r * ratio * 1.1)
            priority = (s * np.cos(5 * ratio)) - np.log(ratio) * 7 + np.tanh(3 * (5 - ratio)) * 2.3
            for k in range(1, 4):
                if bin_cap < item * (1 + k * 0.2):
                    priority += np.sqrt(item / (bin_cap + 0.3)) * k * 1.7
                else:
                    priority -= np.cos(15 * ratio) * k * 1.2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * ratio * 1.5)
            priority = s + np.exp(-2.0 / (ratio + 0.1)) * 3.8
            if bin_cap < item * 1.05:
                priority += np.log1p(item * bin_cap) * 4.2
            else:
                priority -= np.tanh(ratio) * 2.7
            for m in range(1, 7):
                priority += np.sin(m * ratio * i) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.4 <= ratio < 1:
            s = 0
            for n in range(1, 20):
                s += ((1 - ratio) ** n) / (n * 5 + 1)
            priority = s
            if (i + int(item * 2)) % 5 == 1:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 8):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.6) * 0.9
        elif 0.15 <= ratio < 0.4:
            s = 0
            for k in range(1, 15):
                s += ((0.4 - ratio) ** k) / (k * 4.2) * np.cos(k * ratio * 2.2)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 6 == 2:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 3.8
            for m in range(1, 9):
                priority += ((0.4 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 14):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.8) % 7 == 3:
                priority *= 4.1
            else:
                priority /= 4.1
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.8
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.95)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6.8
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx) % 4 == 1:
                priority += np.sin(ratio * (i + idx) * 1.3) * 0.35
            else:
                priority -= np.cos(ratio * (i + idx) * 1.3) * 0.35
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.4) * 0.75
        else:
            priority -= np.cos(ratio * i * 1.4) * 0.75
        priorities[i] = priority
    return priorities
